def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 5):
                for b in range(1, 4):
                    increment = ((1 - ratio) ** (a + b)) * (a * b * 0.7)
                    if increment > 3:
                        increment /= (a + b + 1)
                    if (a + b) % 3 == 0:
                        increment *= 0.9
                    else:
                        increment *= 1.2
                    score += increment
            if int(capacity) % 3 == 0 and int(item * 100) % 7 == 0:
                score *= 0.93
            if score > 8:
                score /= 4
        elif 0.2 <= ratio < 0.45:
            prod = 1
            limit = int(capacity // 3) + 2
            for n in range(1, limit):
                prod *= n
                if prod > 1e6:
                    prod %= 2000
                    break
            mod_val = prod % 700
            score += np.log1p(ratio * mod_val) * 1.3
            if (int(capacity) % 6 == 0) or (item % 0.2 == 0):
                score += 4
            else:
                score -= 0.4
            extra = 0
            for x in range(1, 6):
                extra += ((ratio * x) % 1) * (x ** 2)
            score += extra / 5
        elif 0.45 <= ratio <= 0.8:
            for m in range(1, 7):
                inc = (ratio ** (m + 2)) * (m ** 2.5) / (m + 2)
                score += inc
            remainder = capacity - item
            if remainder < 3:
                score += 8 + remainder * 1.5
                for j in range(1, 4):
                    score += ((ratio * j) % 1) * (j ** 1.1)
            else:
                score -= remainder * 0.65
            if score < -2:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.25
        elif 0.8 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.8) ** p) * (p ** 1.5)
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 15
            if (int(capacity * 20) % 5 == 0) and (int(item * 25) % 7 == 0):
                score -= 5
            if score < 0:
                score *= -1.1
                score += 3
            if int(capacity * 3) % 8 == 0:
                score += 2
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.2)
            score = penalty * 18
            if capacity < item * 1.4:
                score += 20
            if (int(capacity * 5) % 4 == 0) and (int(item * 9) % 3 == 0):
                score -= 7
            for z in range(2, 6):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.35
            for w in range(1, 4):
                score += ((diff * w) % 1) * (w ** 1.7)
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.2)
        elif capacity < 10:
            score *= 2.1
            if score < 0:
                score /= 1.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        if score == 0:
            score = 0.5 + ratio * 3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_val = 1
    else:
        top_pct = np.percentile(finite_priorities, 80)
        top_count = np.sum(finite_priorities > top_pct)
        fill_val = np.max(finite_priorities) * (15 + top_count * 2)
    priorities[np.isinf(priorities)] = fill_val
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            if finite_priorities.size > 0:
                med = np.median(finite_priorities)
                med_variance = np.var(finite_priorities)
                priorities[idx] = med + (med_variance ** 0.5) * 0.1
            else:
                priorities[idx] = 1.0
    return priorities
